### Programmatic Focus Control with useFocusManager Hook (Ink)

Source: https://context7.com/vadimdemedes/ink/llms.txt

The useFocusManager hook provides methods to control the focus system programmatically, including enabling/disabling it and navigating between focusable components. This is essential for implementing custom focus behaviors and complex navigation flows within Ink applications.

```javascript
import React, {useState} from 'react';
import {render, useFocus, useFocusManager, useInput, Box, Text} from 'ink';

function MenuItem({id, label}) {
  const {isFocused} = useFocus({id});
  return (
    <Text color={isFocused ? 'green' : 'white'}>
      {isFocused ? '→ ' : '  '}{label}
    </Text>
  );
}

function Menu() {
  const {focusNext, focusPrevious, focus, enableFocus, disableFocus} = useFocusManager();
  const [menuActive, setMenuActive] = useState(true);

  useInput((input, key) => {
    if (key.upArrow) focusPrevious();
    if (key.downArrow) focusNext();

    // Jump to specific item
    if (input === '1') focus('home');
    if (input === '2') focus('settings');
    if (input === '3') focus('exit');

    // Toggle focus system
    if (input === 'd') {
      setMenuActive(false);
      disableFocus();
    }
    if (input === 'e') {
      setMenuActive(true);
      enableFocus();
    }
  });

  return (
    <Box flexDirection="column">
      <Text bold>Menu {menuActive ? '(Active)' : '(Disabled)'}</Text>
      <MenuItem id="home" label="Home" />
      <MenuItem id="settings" label="Settings" />
      <MenuItem id="exit" label="Exit" />
      <Text dimColor marginTop={1}>
        ↑↓: Navigate | 1-3: Jump | d: Disable | e: Enable
      </Text>
    </Box>
  );
}

render(<Menu />);
```

